```tsx
/**
 * @vitest-environment jsdom
 */
import { describe, it, expect, vi } from 'vitest';
import { renderHook, waitFor } from '@testing-library/react';
import { QueryClient, QueryClientProvider } from '@tanstack/react-query';
import { TransportProvider } from '@/layers/shared/model';
import { createMockTransport } from '@dorkos/test-utils';
import { useTestBinding } from '../use-test-binding';

function createWrapper(transport: ReturnType<typeof createMockTransport>) {
  const queryClient = new QueryClient({ defaultOptions: { queries: { retry: false } } });
  return ({ children }: { children: React.ReactNode }) => (
    <QueryClientProvider client={queryClient}>
      <TransportProvider transport={transport as any}>{children}</TransportProvider>
    </QueryClientProvider>
  );
}

describe('useTestBinding', () => {
  it('calls transport.testBinding with the provided binding id', async () => {
    const mockResult = { ok: true, resolved: true, latencyMs: 42, wouldDeliverTo: 'agent-1', details: 'Routing succeeded.' };
    const transport = createMockTransport({ testBinding: vi.fn().mockResolvedValue(mockResult) });
    const { result } = renderHook(() => useTestBinding(), { wrapper: createWrapper(transport) });

    result.current.mutate('binding-123');

    await waitFor(() => expect(result.current.isSuccess).toBe(true));
    expect(transport.testBinding).toHaveBeenCalledWith('binding-123');
    expect(result.current.data).toEqual(mockResult);
  });

  it('handles test failure result', async () => {
    const mockResult = { ok: false, resolved: false, latencyMs: 10, reason: 'Agent not found' };
    const transport = createMockTransport({ testBinding: vi.fn().mockResolvedValue(mockResult) });
    const { result } = renderHook(() => useTestBinding(), { wrapper: createWrapper(transport) });

    result.current.mutate('binding-456');

    await waitFor(() => expect(result.current.isSuccess).toBe(true));
    expect(result.current.data?.ok).toBe(false);
  });

  it('handles network error', async () => {
    const transport = createMockTransport({ testBinding: vi.fn().mockRejectedValue(new Error('Network error')) });
    const { result } = renderHook(() => useTestBinding(), { wrapper: createWrapper(transport) });

    result.current.mutate('binding-789');

    await waitFor(() => expect(result.current.isError).toBe(true));
    expect(result.current.error?.message).toBe('Network error');
  });
});
```

