```tsx
import { formatRelativeTime } from '@/layers/shared/lib';

// Add state for forcing re-render of relative time
const [, setTick] = useState(0);

useEffect(() => {
  if (!lastMessageAt || isPaused) return;
  const interval = setInterval(() => setTick((t) => t + 1), 60_000);
