**Step 4 — Add handleTest handler:**

```ts
const handleTest = useCallback(
  async (binding: AdapterBinding) => {
    try {
      const result = await testBinding.mutateAsync(binding.id);
      if (result.ok) {
        toast.success(`Test OK — routed in ${result.latencyMs}ms`);
      } else {
        toast.error(`Test failed: ${result.reason ?? 'Unknown error'}`);
      }
      return result;
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Test failed';
      // Check for 409 (paused) from server
      if (message.includes('paused')) {
        toast.error('Test blocked — binding is paused. Resume it first.');
      } else {
        toast.error(`Test failed: ${message}`);
      }
      throw err;
    }
  },
  [testBinding]
);
```

**Step 5 — Compute lastMessageAt per binding:**

For each binding, we need the latest `lastMessageAt` from observed chats for that adapter. This requires calling `useObservedChats` per adapter. Since hooks can't be called in loops, extract this into a sub-component or compute it at the ChannelsTab level using the existing catalog data.

**Preferred approach:** Create a small wrapper component `BoundChannelRow` that handles the per-binding data fetching:

```tsx
function BoundChannelRow({
  binding,
  display,
  onEdit,
  onRemove,
  onTogglePause,
  onTest,
}: {
  binding: AdapterBinding;
  display: AdapterDisplay;
  onEdit: () => void;
  onRemove: () => void;
  onTogglePause: (enabled: boolean) => void;
  onTest: () => Promise<BindingTestResult>;
}) {
  const { data: observedChats = [] } = useObservedChats(binding.adapterId);

  const lastMessageAt = useMemo(() => {
    if (observedChats.length === 0) return undefined;
    // If the binding has a specific chatId filter, use that chat's timestamp;
    // otherwise, use the newest across all observed chats.
    if (binding.chatId) {
      const match = observedChats.find((c) => c.chatId === binding.chatId);
      return match?.lastMessageAt;
    }
    return observedChats
      .map((c) => c.lastMessageAt)
      .reduce<string | undefined>((newest, ts) => {
        if (!newest) return ts;
        return ts > newest ? ts : newest;
      }, undefined);
  }, [binding.chatId, observedChats]);

  return (
    <ChannelBindingCard
      binding={binding}
      channelName={display.name}
      adapterState={display.state}
      errorMessage={display.errorMessage}
      lastMessageAt={lastMessageAt}
      onTogglePause={onTogglePause}
      onTest={onTest}
      onEdit={onEdit}
      onRemove={onRemove}
    />
  );
}
```

**Step 6 — Update the render loop:**

Replace the current `agentBindings.map(...)` block with:

